import React, { useState, useEffect } from 'react';
import './Certificates.css';

interface Certificate {
  _id?: string;
  title: string;
  issuer: string;
  date: string;
  credentialId: string;
  credentialUrl: string;
  imageUrl: string;
}

const Certificates: React.FC = () => {
  const [certificates, setCertificates] = useState<Certificate[]>([
    {
      title: 'Full Stack Web Development',
      issuer: 'freeCodeCamp',
      date: 'March 2024',
      credentialId: 'FCP123456789',
      credentialUrl: 'https://freecodecamp.org/certification/username/full-stack',
      imageUrl: '/certificate1.jpg'
    },
    {
      title: 'React - The Complete Guide',
      issuer: 'Udemy',
      date: 'February 2024',
      credentialId: 'UC-987654321',
      credentialUrl: 'https://udemy.com/certificate/UC-987654321',
      imageUrl: '/certificate2.jpg'
    },
    {
      title: 'MongoDB Basics',
      issuer: 'MongoDB University',
      date: 'January 2024',
      credentialId: 'MONGO-BASIC-2024',
      credentialUrl: 'https://university.mongodb.com/certificate/MONGO-BASIC-2024',
      imageUrl: '/certificate3.jpg'
    },
    {
      title: 'Advanced JavaScript',
      issuer: 'Coursera',
      date: 'December 2023',
      credentialId: 'COURSERA-JS-ADV',
      credentialUrl: 'https://coursera.org/verify/COURSERA-JS-ADV',
      imageUrl: '/certificate4.jpg'
    },
    {
      title: 'Node.js Developer',
      issuer: 'edX',
      date: 'November 2023',
      credentialId: 'EDX-NODEJS-2023',
      credentialUrl: 'https://edx.org/certificate/EDX-NODEJS-2023',
      imageUrl: '/certificate5.jpg'
    },
    {
      title: 'TypeScript Fundamentals',
      issuer: 'Pluralsight',
      date: 'October 2023',
      credentialId: 'PS-TS-FUND-2023',
      credentialUrl: 'https://pluralsight.com/certificate/PS-TS-FUND-2023',
      imageUrl: '/certificate6.jpg'
    },
    {
      title: 'The Joy of Computing using Python',
      issuer: 'NPTEL · IIT Madras',
      date: '2021',
      credentialId: 'Elite certificate (NPTEL Online Certification)',
      credentialUrl: 'https://nptel.ac.in/certificate',
      imageUrl: '/python-nptel-certificate.jpg'
    }
  ]);

  useEffect(() => {
    const fetchCertificates = async () => {
      try {
        const response = await fetch('/api/certificates');
        if (response.ok) {
          const data = await response.json();
          if (data && data.length > 0) {
            setCertificates(data);
          }
        }
      } catch (error) {
        console.log('Using default certificates, API not available');
      }
    };

    fetchCertificates();
  }, []);

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const target = e.target as HTMLImageElement;
    target.src = 'data:image/svg+xml;base64,';
  };

  return (
    <div className="certificates">
      <div className="container">
        <h1 className="page-title">My Certificates</h1>
        <p className="page-subtitle">
          Professional certifications and achievements that showcase my continuous learning and expertise in various technologies.
        </p>

        <div className="certificates-grid">
          {certificates.map((certificate, index) => (
            <div key={certificate._id || index} className="certificate-card">
              <div className="certificate-image">
                <img 
                  src={certificate.imageUrl} 
                  alt={certificate.title}
                  onError={handleImageError}
                />
              </div>

              <div className="certificate-content">
                <h3>{certificate.title}</h3>
                <div className="certificate-meta">
                  <div className="issuer">
                    <strong>Issuer:</strong> {certificate.issuer}
                  </div>
                  <div className="date">
                    <strong>Date:</strong> {certificate.date}
                  </div>
                  {certificate.credentialId && (
                    <div className="credential-id">
                      <strong>ID:</strong> {certificate.credentialId}
                    </div>
                  )}
                </div>

                <div className="certificate-actions">
                  <a 
                    href={certificate.credentialUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-primary"
                  >
                    Verify Certificate
                  </a>
                </div>
              </div>
            </div>
          ))}
        </div>

        {certificates.length === 0 && (
          <div className="no-certificates">
            <p>No certificates available at the moment.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Certificates;
